import http from "node:http";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { startLoopbackServer } from "./loopback.js";
async function getOpenPort() {
    return new Promise((resolve, reject) => {
        const server = http.createServer();
        server.listen(0, () => {
            const addr = server.address();
            server.close(() => resolve(addr.port));
        });
        server.on("error", reject);
    });
}
describe("startLoopbackServer", () => {
    let loopback = null;
    beforeEach(() => {
        loopback = null;
    });
    afterEach(() => {
        loopback?.close();
    });
    it("resolves the promise when a route handler calls resolve", async () => {
        const port = await getOpenPort();
        loopback = await startLoopbackServer(port, [
            {
                path: "/callback",
                handle: (params, res, resolve) => {
                    const token = params.get("token");
                    res.writeHead(200);
                    res.end("ok");
                    if (token) {
                        resolve(token);
                    }
                },
            },
        ]);
        await fetch(`http://localhost:${port}/callback?token=abc123`);
        await expect(loopback.promise).resolves.toBe("abc123");
        expect(loopback.done).toBe(true);
    });
    it("serves /health by default", async () => {
        const port = await getOpenPort();
        loopback = await startLoopbackServer(port, []);
        const res = await fetch(`http://localhost:${port}/health`);
        expect(res.status).toBe(200);
        expect(await res.json()).toEqual({ ok: true });
        expect(loopback.done).toBe(false);
    });
    it("returns 404 for unknown routes", async () => {
        const port = await getOpenPort();
        loopback = await startLoopbackServer(port, []);
        const res = await fetch(`http://localhost:${port}/nope`);
        expect(res.status).toBe(404);
    });
    it("handles OPTIONS preflight with CORS headers", async () => {
        const port = await getOpenPort();
        loopback = await startLoopbackServer(port, []);
        const res = await fetch(`http://localhost:${port}/anything`, {
            method: "OPTIONS",
        });
        expect(res.status).toBe(204);
        expect(res.headers.get("access-control-allow-origin")).toBe("*");
    });
    it("only resolves once even if a route handler is called twice", async () => {
        const port = await getOpenPort();
        loopback = await startLoopbackServer(port, [
            {
                path: "/callback",
                handle: (params, res, resolve) => {
                    res.writeHead(200);
                    res.end("ok");
                    const token = params.get("token");
                    if (token) {
                        resolve(token);
                    }
                },
            },
        ]);
        await fetch(`http://localhost:${port}/callback?token=first`);
        await fetch(`http://localhost:${port}/callback?token=second`);
        await expect(loopback.promise).resolves.toBe("first");
    });
    it("exposes resolve/reject for external callers (e.g. stdin paste)", async () => {
        const port = await getOpenPort();
        loopback = await startLoopbackServer(port, []);
        loopback.resolve("from-outside");
        await expect(loopback.promise).resolves.toBe("from-outside");
    });
    it("rejects the promise when reject is called", async () => {
        const port = await getOpenPort();
        loopback = await startLoopbackServer(port, []);
        loopback.reject(new Error("timed out"));
        await expect(loopback.promise).rejects.toThrow("timed out");
    });
    it("returns available:true and null bindError when bind succeeds", async () => {
        const port = await getOpenPort();
        loopback = await startLoopbackServer(port, []);
        expect(loopback.available).toBe(true);
        expect(loopback.bindError).toBeNull();
    });
    it("returns available:false with bindError when the port is already in use", async () => {
        const port = await getOpenPort();
        const blocker = http.createServer();
        // Blocker must claim the same host the real server binds to
        // (127.0.0.1), otherwise on macOS the default IPv6 bind leaves the
        // IPv4 loopback free and startLoopbackServer succeeds.
        await new Promise((resolve) => blocker.listen(port, "127.0.0.1", resolve));
        try {
            loopback = await startLoopbackServer(port, []);
            expect(loopback.available).toBe(false);
            expect(loopback.bindError).toBeInstanceOf(Error);
            expect(loopback.bindError?.message).toMatch(/EADDRINUSE/);
            loopback.resolve("paste-fallback");
            await expect(loopback.promise).resolves.toBe("paste-fallback");
            loopback.close();
        }
        finally {
            await new Promise((resolve) => blocker.close(() => resolve()));
        }
    });
});
